                            {[0, 1, 8, 10, 18, 20].map(rate => (
                              <option key={rate} value={rate}>
                                {'%' + rate + ' KDV' + (rate === 0 ? ' — İstisna/İhracat' : rate === 1 ? ' — Temel Gıda' : rate === 8 ? ' — İndirimli' : rate === 20 ? ' — Genel Oran' : '')}
                              </option>
                            ))}
